code = """import json
import os

# Load the full dataset from the file path
file_path = locals()['var_functions.query_db:32']
with open(file_path, 'r') as f:
    articles = json.load(f)

print('Total articles loaded: %d' % len(articles))

# Define sports indicators - check if any of these appear
sports_terms = [
    'football', 'soccer', 'basketball', 'baseball', 'tennis', 'golf',
    'racing', 'race', 'olympic', 'game', 'team', 'player', 'coach', 'match',
    'athlete', 'championship', 'tournament', 'grand', 'prix', 'marathon'
]

# Search for sports articles
sports_articles = []

for i, article in enumerate(articles):
    # Combine title and description
    text = (article['title'] + ' ' + article['description']).lower()
    
    # Check if any sports term appears
    sports_score = 0
    matching_terms = []
    
    for term in sports_terms:
        if term in text:
            sports_score += 1
            matching_terms.append(term)
    
    if sports_score > 0:
        sports_articles.append({
            'index': i,
            'title': article['title'],
            'length': len(article['description']),
            'score': sports_score,
            'terms': matching_terms
        })

print('Articles with sports indicators: %d' % len(sports_articles))

if sports_articles:
    # Sort by description length
    sports_articles.sort(key=lambda x: x['length'], reverse=True)
    
    print('\nTop 10 sports articles by description length:')
    for i, article in enumerate(sports_articles[:10]):
        print('%d. "%s" (len: %d, score: %d)' % (
            i+1, article['title'][:60], article['length'], article['score']))
        print('   Matching: %s' % ', '.join(article['terms']))

if sports_articles:
    answer = sports_articles[0]['title']
    print('\nLongest sports article: %s' % answer)
else:
    answer = 'No sports articles found'
    print('\n%s' % answer)

print('__RESULT__:')
print(json.dumps(answer))"""

